//     "TWILIO_PHONE_NUMBER": "<your-twilio-phone-number>"
//   }
// }

const sgMail = require("@sendgrid/mail");
const twilio = require("twilio");

module.exports = async function (context, req) {
    const sendgridApiKey = process.env.SENDGRID_API_KEY;
    const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
    const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
    const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;

    // Validate that required configuration is present
    const missingVars = [];
    if (!sendgridApiKey) missingVars.push("SENDGRID_API_KEY");
    if (!twilioAccountSid) missingVars.push("TWILIO_ACCOUNT_SID");
    if (!twilioAuthToken) missingVars.push("TWILIO_AUTH_TOKEN");
    if (!twilioPhoneNumber) missingVars.push("TWILIO_PHONE_NUMBER");

    if (missingVars.length > 0) {
        context.res = {
            status: 500,
            body: {
                error: "Missing required environment variables",
                missing: missingVars,
                hint: "Set these in local.settings.json (local) or Application Settings (Azure)"
            }
        };
        return;
    }

    const { type, to, subject, body, message } = req.body || {};

    if (!type || !to) {
        context.res = {
            status: 400,
            body: {
                error: "Missing required fields",
                usage: {
                    email: { type: "email", to: "recipient@example.com", subject: "Subject", body: "Email body" },
                    sms: { type: "sms", to: "+1234567890", message: "SMS message" }
                }
            }
        };
        return;
    }

    try {
        if (type === "email") {
            if (!subject || !body) {
                context.res = {
                    status: 400,
                    body: { error: "Email requires 'subject' and 'body' fields" }
                };
                return;
            }

            sgMail.setApiKey(sendgridApiKey);

            const emailMessage = {
                to: to,
                from: req.body.from || "noreply@yourdomain.com",
                subject: subject,
                text: body,
                html: req.body.html || `<p>${body}</p>`
            };

            const response = await sgMail.send(emailMessage);
            context.log("SendGrid email sent successfully to:", to);

            context.res = {
                status: 200,
                body: {
                    success: true,
                    channel: "email",
                    to: to,
                    statusCode: response[0].statusCode
                }
            };

        } else if (type === "sms") {
            if (!message) {
                context.res = {
                    status: 400,
                    body: { error: "SMS requires a 'message' field" }
                };
                return;
            }

            const twilioClient = twilio(twilioAccountSid, twilioAuthToken);

            const smsResult = await twilioClient.messages.create({
                body: message,
                from: twilioPhoneNumber,
                to: to
            });

            context.log("Twilio SMS sent successfully. SID:", smsResult.sid);

            context.res = {
                status: 200,
                body: {
                    success: true,
                    channel: "sms",
                    to: to,
                    messageSid: smsResult.sid,
                    status: smsResult.status
                }
            };

        } else {
            context.res = {
                status: 400,
                body: { error: "Invalid type. Use 'email' or 'sms'." }
            };
        }

    } catch (error) {
        context.log.error("Notification failed:", error.message);

        context.res = {
            status: 500,
            body: {
                success: false,
                error: "Failed to send notification",
                details: error.message
            }
        };
    }
};